SELECT COUNT(*) AS shared_indexes_count
FROM shared_indexes
WHERE JULIANDAY('now') - JULIANDAY(shared_at) <= 30;

SELECT index_name, index_size
FROM indexes
WHERE index_size = (SELECT MAX(index_size) FROM indexes);

SELECT index_id, index_name
FROM indexes
WHERE index_status = 'under maintenance';

SELECT COUNT(stat_id) 
FROM indexing_statistics 
WHERE indexing_errors > 0;

SELECT index_name, index_type
FROM indexes
WHERE index_status = 'under maintenance';

SELECT index_status, COUNT(*) AS status_count
FROM indexes
GROUP BY index_status;

SELECT * 
FROM shared_indexing_statistics 
WHERE total_indexing_time > 20;
